import React, { useState } from "react";

export default function SavingsWithdrawScreen({ savingsBalance, onWithdraw }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    if (!amount || isNaN(amount) || Number(amount) <= 0) {
      alert("Enter a valid amount");
      return;
    }
    if (Number(amount) > savingsBalance) {
      alert("Insufficient savings balance");
      return;
    }
    onWithdraw(Number(amount));
    setAmount("");
    alert(`Withdrew $${amount} from savings!`);
  };

  return (
    <div className="p-6 pb-24 animate-fade-in">
      <h1 className="text-2xl font-bold mb-4">Withdraw from Savings</h1>
      <input
        type="number"
        placeholder="Enter amount"
        value={amount}
        onChange={(e) => setAmount(e.target.value)}
        className="w-full mb-4 p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
      />
      <button
        onClick={handleWithdraw}
        className="w-full bg-red-600 text-white py-3 rounded-lg hover:bg-red-700 transition-colors"
      >
        Withdraw from Savings
      </button>
    </div>
  );
}
